    parameter R = 127,
    parameter W = 5,
    parameter POS_W = 8,
    parameter MAX_IT = 10,
    parameter THRESHOLD = 2
)(
    input wire clk,
    input wire rst,
    input wire start,

    input  wire [R-1:0]     s_in,

