    input  wire [W*POS_W-1:0] h1_pos_flat,

    output reg  [R-1:0]     e0,
    output reg  [R-1:0]     e1,
    output reg              done,
    output reg              success
);

// =====================================================
// Unflatten sparse positions
// =====================================================
wire [POS_W-1:0] h0_pos [0:W-1];
wire [POS_W-1:0] h1_pos [0:W-1];

genvar gi;
generate
    for (gi = 0; gi < W; gi = gi + 1) begin
        assign h0_pos[gi] = h0_pos_flat[gi*POS_W +: POS_W];
        assign h1_pos[gi] = h1_pos_flat[gi*POS_W +: POS_W];
    end
endgenerate

// =====================================================
// Registers
// =====================================================
reg [R-1:0] syndrome;
reg [$clog2(R)-1:0] i;
reg [$clog2(W)-1:0] k;
reg [$clog2(MAX_IT)-1:0] iter;
reg [3:0] vote0, vote1;
reg any_flipped;
reg flip0_reg, flip1_reg;


wire [POS_W:0] sum0 = i + h0_pos[k];
wire [POS_W:0] sum1 = i + h1_pos[k];
wire [$clog2(R)-1:0] idx0 = (sum0 >= R) ? (sum0 - R) : sum0[ $clog2(R)-1:0 ];
//wire [$clog2(R)-1:0] idx0; 
//assign idx0 = (i + h0_pos[k]) % R;
wire [$clog2(R)-1:0] idx1 = (sum1 >= R) ? (sum1 - R) : sum1[ $clog2(R)-1:0 ];
//wire [$clog2(R)-1:0] idx1;
//assign idx1 = (i + h1_pos[k]) % R;
// =====================================================
// FSM
// =====================================================
localparam IDLE        = 3'd0,
           VOTE        = 3'd1,
           FLIP_PREP   = 3'd2,
           FLIP_UPDATE = 3'd3,
           NEXT_I      = 3'd4,
           CHECK_ITER  = 3'd5,
           DONE        = 3'd6;

reg [2:0] state;

// always @(i)begin
//     $display( "i=%0d, k=%0d, syndrome=%b, e0=%b, e1=%b", i, k, syndrome, e0, e1);
// end

// always @(k)begin
//     $display(" idx0:%0d, k:%d, pos:%d", idx0, k, h0_pos[k]);    //sai ngay chỗ truy cập pos này
// end
always @(posedge clk or posedge rst) begin
    if (rst) begin
        state       <= IDLE;
        e0          <= 0;
        e1          <= 0;
        syndrome    <= 0;
        i           <= 0;
        k           <= 0;
        iter        <= 0;
        vote0       <= 0;
        vote1       <= 0;
        any_flipped <= 0;
        flip0_reg   <= 0;
        flip1_reg   <= 0;
        done        <= 0;
        success     <= 0;
    end else begin
        case (state)
            IDLE: begin
                done <= 0;
                success <= 0;
                if (start) begin
                    e0          <= 0;
                    e1          <= 0;
                    syndrome    <= s_in;
                    i           <= 0;
                    k           <= 0;
                    iter        <= 0;
                    any_flipped <= 0;
                    state       <= VOTE;
                end
            end

            VOTE: begin

                if (k == 0) begin
                    vote0 <= syndrome[idx0];
                    vote1 <= syndrome[idx1];
                end else begin
                    vote0 <= vote0 + syndrome[idx0];
                    vote1 <= vote1 + syndrome[idx1];
                end

                if (k == W - 1) begin
                    k     <= 0;
                    state <= FLIP_PREP;
                end else begin
                    k <= k + 1;
                end
            end

            FLIP_PREP: begin
                flip0_reg <= (vote0 >= THRESHOLD);
                flip1_reg <= (vote1 >= THRESHOLD);
                if (vote0 >= THRESHOLD || vote1 >= THRESHOLD)
                    any_flipped <= 1;
                k <= 0;
                state <= FLIP_UPDATE;  
            end

            FLIP_UPDATE: begin
                if (flip0_reg && flip1_reg && (idx0 == idx1)) begin
                    // XORing twice cancels out
                end else begin
                    if (flip0_reg) syndrome[idx0] <= ~syndrome[idx0];
                    if (flip1_reg) syndrome[idx1] <= ~syndrome[idx1];
                end

                if (k == 0) begin
                    if (flip0_reg) e0[i] <= ~e0[i];
                    if (flip1_reg) e1[i] <= ~e1[i];
                end

                if (k == W - 1) begin
                    k <= 0;
                    state <= NEXT_I;
                end else begin
                    k <= k + 1;
                end
            end

            NEXT_I: begin
                vote0 <= 0;
                vote1 <= 0;
                if (i == R - 1) begin
                    state <= CHECK_ITER;
                end else begin
                    i <= i + 1;
                    k <= 0;
                    state <= VOTE;
                end
            end

            CHECK_ITER: begin
                if (syndrome == 0) begin
                    success <= 1;
                    state <= DONE;
                end else if (!any_flipped || iter == MAX_IT - 1) begin
                    success <= 0;
                    state <= DONE;
                end else begin
                    iter <= iter + 1;
                    i <= 0;
                    k <= 0;
                    any_flipped <= 0;
                    state <= VOTE;
                end
            end

            DONE: begin
                done <= 1;
                if (!start) state <= IDLE;
            end

            default: state <= IDLE;
        endcase
    end
end

endmodule






