                    end else begin
                        round_cnt <= round_cnt + 1;
                    end
                end
                FINISH: begin
                    done <= 1'b1;
                    out_state <= curr_state;
                    state <= IDLE;
                end
                default: begin
                    state <= IDLE;
                end
            endcase
        end
    end


